using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public static class TicketModelTrainer
{
    public static TrainingResult TrainAndEvaluate(string dataPath, string modelPath)
    {
        var mlContext = new MLContext(seed: 42);

        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate(
                "Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                "Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        // Extract label ordering from the trained model's Score column metadata
        var outputSchema = model.GetOutputSchema(data.Schema);
        var scoreColumn = outputSchema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.GetSlotNames(ref slotNames);
        var labels = slotNames.DenseValues().Select(x => x.ToString()).ToArray();

        mlContext.Model.Save(model, data.Schema, modelPath);

        return new TrainingResult
        {
            Labels = labels,
            MicroAccuracy = metrics.MicroAccuracy,
            MacroAccuracy = metrics.MacroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction,
            ConfusionMatrix = metrics.ConfusionMatrix.GetFormattedConfusionTable()
        };
    }
}

public class TrainingResult
{
    public string[] Labels { get; set; } = [];
    public double MicroAccuracy { get; set; }
    public double MacroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public string ConfusionMatrix { get; set; } = string.Empty;
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private readonly TrainingResult _trainingResult;

    public TicketController(
        PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
        TrainingResult trainingResult)
    {
        _predictionPool = predictionPool;
        _trainingResult = trainingResult;
    }

    [HttpPost("classify")]
    public ActionResult<TicketClassificationResult> Classify([FromBody] TicketRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);
        var confidence = _trainingResult.Labels
            .Zip(prediction.Score)
            .ToDictionary(pair => pair.First, pair => pair.Second);

        return Ok(new TicketClassificationResult
        {
            Category = prediction.Category,
            Confidence = confidence
        });
    }
}

